section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/agency-valuation-rubric.json",
  "title": "Agency Valuation Rubric",
  "type": "object",
  "required": [
    "artefact_id",
    "target_name",
    "ebitda_usd",
    "scores",
    "weighted_total",
    "multiplier",
    "evidence",
    "decision",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "target_name": {
      "type": "string",
      "description": "agency under review",
      "minLength": 1
    },
    "ebitda_usd": {
      "type": "number",
      "description": "trailing-12-month EBITDA"
    },
    "scores": {
      "type": "object",
      "description": "criterion \u2192 {score:1-5, weight, citation}"
    },
    "weighted_total": {
      "type": "number",
      "description": "0-100 sum"
    },
    "multiplier": {
      "type": "number",
      "description": "derived EBITDA multiplier"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "decision": {
      "type": "string",
      "description": "advance|reject|prioritize",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
